import{_ as a,o as s,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"RPC Adapters","description":"","frontmatter":{"summary":"RPC adapters for external CLIs (signal-cli, legacy imsg) and gateway patterns","read_when":["Adding or changing external CLI integrations","Debugging RPC adapters (signal-cli, imsg)"],"title":"RPC Adapters"},"headers":[],"relativePath":"reference/rpc.md","filePath":"reference/rpc.md","lastUpdated":null}'),r={name:"reference/rpc.md"};function l(o,e,n,d,c,p){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="rpc-adapters" tabindex="-1"><a class="header-anchor" href="#rpc-adapters">#</a> RPC adapters</h1><p>OpenSoul integrates external CLIs via JSON-RPC. Two patterns are used today.</p><h2 id="pattern-a-http-daemon-signal-cli" tabindex="-1"><a class="header-anchor" href="#pattern-a-http-daemon-signal-cli">#</a> Pattern A: HTTP daemon (signal-cli)</h2><ul><li><code>signal-cli</code> runs as a daemon with JSON-RPC over HTTP.</li><li>Event stream is SSE (<code>/api/v1/events</code>).</li><li>Health probe: <code>/api/v1/check</code>.</li><li>OpenSoul owns lifecycle when <code>channels.signal.autoStart=true</code>.</li></ul><p>See <a href="/docs/channels/signal">Signal</a> for setup and endpoints.</p><h2 id="pattern-b-stdio-child-process-legacy-imsg" tabindex="-1"><a class="header-anchor" href="#pattern-b-stdio-child-process-legacy-imsg">#</a> Pattern B: stdio child process (legacy: imsg)</h2><blockquote><p><strong>Note:</strong> For new iMessage setups, use <a href="/docs/channels/bluebubbles">BlueBubbles</a> instead.</p></blockquote><ul><li>OpenSoul spawns <code>imsg rpc</code> as a child process (legacy iMessage integration).</li><li>JSON-RPC is line-delimited over stdin/stdout (one JSON object per line).</li><li>No TCP port, no daemon required.</li></ul><p>Core methods used:</p><ul><li><code>watch.subscribe</code> → notifications (<code>method: &quot;message&quot;</code>)</li><li><code>watch.unsubscribe</code></li><li><code>send</code></li><li><code>chats.list</code> (probe/diagnostics)</li></ul><p>See <a href="/docs/channels/imessage">iMessage</a> for legacy setup and addressing (<code>chat_id</code> preferred).</p><h2 id="adapter-guidelines" tabindex="-1"><a class="header-anchor" href="#adapter-guidelines">#</a> Adapter guidelines</h2><ul><li>Gateway owns the process (start/stop tied to provider lifecycle).</li><li>Keep RPC clients resilient: timeouts, restart on exit.</li><li>Prefer stable IDs (e.g., <code>chat_id</code>) over display strings.</li></ul>',13)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
